import{_ as a,o,c as l,a3 as t}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"93. Uniform Allowance","description":"","frontmatter":{"title":"93. Uniform Allowance","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["allowances","uniforms"]},"headers":[],"relativePath":"ebas/mspp/accident-pay-allowances/93-uniform-allowance.md","filePath":"ebas/mspp/accident-pay-allowances/93-uniform-allowance.md"}'),r={name:"ebas/mspp/accident-pay-allowances/93-uniform-allowance.md"};function n(s,e,i,p,h,c){return o(),l("div",null,[...e[0]||(e[0]=[t('<h1 id="_93-uniform-allowance" tabindex="-1">93. Uniform Allowance <a class="header-anchor" href="#_93-uniform-allowance" aria-label="Permalink to &quot;93. Uniform Allowance&quot;">​</a></h1><p><strong>a.</strong> The Employer shall reimburse the cost of a minimum of two washable coats per week. However, where Pharmacists are provided with minimum of two washable coats per week, the allowance shall not apply. Where a Locum is required to provide their own coats the Employer shall reimburse the laundering cost to the Locum, except where the laundering is arranged by the Employer at the Employer’s cost.</p><p><strong>b.</strong> Where the Employer requires an Employee to wear any special clothing, the Employer must pay the uniform allowance prescribed by this clause for purchasing such clothing. The provisions of this clause do not apply where the special clothing is paid for by the Employer.</p><p><strong>c.</strong> Special clothing shall remain the property of the Employer. If the Employee is responsible for laundering it the Employer must pay the laundry allowance prescribed in <a href="/eba/ebas/mspp/schedules/2-rates-of-pay-and-allowances.html">Schedule 2</a>. This allowance is not payable where the Employer launders and maintains the special clothing.</p><p><strong>d.</strong> In lieu of the provision of special clothing the Employer may, by agreement with the Employee, pay such Employee a uniform allowance as prescribed by <a href="/eba/ebas/mspp/schedules/2-rates-of-pay-and-allowances.html">Schedule 2</a>. Where such Employee’s uniforms are not laundered by or at the expense of the Employer, the Employee shall be paid a laundry allowance as prescribed by <a href="/eba/ebas/mspp/schedules/2-rates-of-pay-and-allowances.html">Schedule 2</a>.</p><p><strong>e.</strong> The Uniform Allowance but not the laundry allowance shall be paid during all absences on leave, except absences on Long Service Leave and absence on Personal Leave beyond 21 days. Where, prior to the taking of leave, an Employee was paid a Uniform Allowance other than at the weekly rate, the rate to be paid during absence on leave shall be the average of the allowance paid during the four weeks immediately preceding the taking of leave.</p><p><strong>f.</strong> Where it is necessary that an Employee be provided with rubber gloves, protective clothing and safety appliances, the Employer must reimburse the Employee for the cost of purchasing such clothing. The provisions of this clause do not apply where the protective clothing is supplied to the Employee at the Employer’s expense.</p><p>PSYCHOLOGISTS AND OTHER MATTERS</p><p>Plain language terms: uniform, laundry allowance.</p>',9)])])}const u=a(r,[["render",n]]);export{d as __pageData,u as default};
